import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats')
      .then(r => { setStats(r.data.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const statCard = (label: string, value: number, icon: string, color: string, sub: string, onClick?: () => void) => (
    <div key={label} onClick={onClick}
      style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 16, padding: 22, cursor: onClick ? 'pointer' : 'default', transition: 'all .2s' }}
      onMouseEnter={e => onClick && ((e.currentTarget as HTMLDivElement).style.transform = 'translateY(-2px)')}
      onMouseLeave={e => onClick && ((e.currentTarget as HTMLDivElement).style.transform = 'translateY(0)')}>
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 14 }}>
        <div style={{ width: 44, height: 44, borderRadius: 11, background: color + '18', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20 }}>{icon}</div>
        <span style={{ fontSize: 11, fontWeight: 600, padding: '3px 10px', borderRadius: 99, background: color + '18', color }}>{sub}</span>
      </div>
      <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 36, fontWeight: 700, marginBottom: 4 }}>{value}</div>
      <div style={{ fontSize: 13, color: '#6b7280' }}>{label}</div>
    </div>
  );

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', padding: 80 }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ width: 40, height: 40, border: '3px solid #c9a84c', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 12px' }} />
        <p style={{ color: '#9ca3af', fontSize: 13 }}>Loading...</p>
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700 }}>
          Good day, {user?.name?.split(' ')[0]} 👋
        </h1>
        <p style={{ color: '#9ca3af', fontSize: 13, marginTop: 4 }}>
          {new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
        </p>
      </div>

      {/* Pending Approval Alert */}
      {isStaff && stats && stats.pendingMembers > 0 && (
        <div onClick={() => navigate('/members?status=pending')}
          style={{ background: '#fef3c7', border: '1px solid #f59e0b', borderRadius: 12, padding: '14px 18px', marginBottom: 20, display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer' }}>
          <span style={{ fontSize: 20 }}>⚠️</span>
          <div>
            <div style={{ fontSize: 14, fontWeight: 600, color: '#92400e' }}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{ fontSize: 12, color: '#b45309' }}>Click to review and approve members</div>
          </div>
          <span style={{ marginLeft: 'auto', color: '#b45309', fontSize: 18 }}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* Stats Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 18, marginBottom: 24 }}>
            {statCard('Total Books', stats.totalBooks, '📚', '#3b82f6', 'Library')}
            {statCard('Active Members', stats.totalMembers, '👥', '#10b981', 'Enrolled')}
            {statCard('Books Out', stats.activeBorrows, '📤', '#c9a84c', 'Active')}
            {statCard('Overdue', stats.overdueBorrows, '⚠️', '#ef4444', 'Urgent')}
          </div>

          {/* Recent + Popular */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
            {/* Recent Borrows */}
            <div style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 16, padding: 22 }}>
              <h3 style={{ fontFamily: "'Playfair Display',serif", fontSize: 16, fontWeight: 700, marginBottom: 16 }}>Recent Borrows</h3>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b: any) => (
                <div key={b.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: 10, background: '#f5f0e8', borderRadius: 10, marginBottom: 8 }}>
                  <div style={{ width: 36, height: 36, background: '#1a1a2e', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>📗</div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{b.title}</div>
                    <div style={{ fontSize: 11, color: '#9ca3af' }}>{b.member_name} · {b.account_type}</div>
                  </div>
                  <span style={{ fontSize: 11, fontWeight: 600, padding: '3px 9px', borderRadius: 99, background: b.status === 'returned' ? '#d1fae5' : b.status === 'overdue' ? '#fee2e2' : '#fef3c7', color: b.status === 'returned' ? '#059669' : b.status === 'overdue' ? '#dc2626' : '#d97706' }}>{b.status}</span>
                </div>
              )) : <p style={{ color: '#9ca3af', fontSize: 13 }}>No borrows yet</p>}
            </div>

            {/* Popular Books */}
            <div style={{ background: '#fff', border: '1px solid #e8e0d0', borderRadius: 16, padding: 22 }}>
              <h3 style={{ fontFamily: "'Playfair Display',serif", fontSize: 16, fontWeight: 700, marginBottom: 16 }}>Popular Books</h3>
              {stats.popularBooks.length ? stats.popularBooks.map((b: any, i: number) => (
                <div key={b.title} style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 14 }}>
                  <div style={{ width: 28, height: 28, borderRadius: 7, background: i === 0 ? '#c9a84c' : '#e8e0d0', color: i === 0 ? '#1a1a2e' : '#6b7280', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700, flexShrink: 0 }}>{i + 1}</div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{b.title}</div>
                    <div style={{ fontSize: 11, color: '#9ca3af' }}>{b.author}</div>
                  </div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#c9a84c' }}>{b.borrow_count}×</div>
                </div>
              )) : <p style={{ color: '#9ca3af', fontSize: 13 }}>No data yet</p>}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
